+/// Expression evaluation edge cases
+#[test]
+fn test_conformance_expr_eval_edges() {
+    let fconn = Connection::open(":memory:").unwrap();
+    let rconn = rusqlite::Connection::open_in_memory().unwrap();
+
+    let queries = [
+        // Boolean expressions
+        "SELECT 1 AND 1, 1 AND 0, 0 AND 0",
+        "SELECT 1 OR 0, 0 OR 0, 1 OR 1",
+        "SELECT NOT 1, NOT 0, NOT NULL",
+        // Ternary comparisons
+        "SELECT 1 < 2 AND 2 < 3",
+        "SELECT 1 = 1 AND 2 != 3",
+        // String concatenation
+        "SELECT 'hello' || ' ' || 'world'",
+        "SELECT 1 || 2",
+        "SELECT NULL || 'a'",
+        // Unary operators
+        "SELECT -(-5)",
+        "SELECT +42",
+        "SELECT ~0, ~1, ~(-1)",
+        // Bitwise operations
+        "SELECT 5 & 3, 5 | 3, ~5",
+        "SELECT 1 << 4, 16 >> 2",
+        // Precedence
+        "SELECT 2 + 3 * 4",
+        "SELECT (2 + 3) * 4",
+        "SELECT 10 - 3 - 2",
+        "SELECT 10 / 3",
+        "SELECT 10 % 3",
+        // Mixed numeric operations
+        "SELECT 1 + 1.0",
+        "SELECT TYPEOF(1 + 1.0)",
+        "SELECT 5 / 2, 5.0 / 2, 5 / 2.0",
+    ];
+
+    let mismatches = oracle_compare(&fconn, &rconn, &queries);
+    if !mismatches.is_empty() {
+        for m in &mismatches {
+            eprintln!("{m}\n");
+        }
+        panic!("{} expr eval edge mismatches", mismatches.len());
+    }
+}
